mapper.select:
SELECT

FROM user_addresses
WHERE address_id = #{addressId}
  AND user_id = #{userId}
  AND deleted = 0
LIMIT 1

mapper.delete:
DELETE
FROM user_addresses
WHERE address_id = #{addressId}
  AND user_id = #{userId}

mapper.update:
UPDATE user_addresses
SET sop_requirement_tags_json = #{sopRequirementTagsJson},
    sop_hard_filter_tags = #{sopHardFilterTags},
    sop_remark = #{sopRemark},
    sop_updated_at = #{sopUpdatedAt}
WHERE address_id = #{addressId}
  AND user_id = #{userId}
  AND deleted = 0
